"import { createClient } from '@supabase/supabase-js';
import dotenv from 'dotenv';
import fs from 'fs';
import path from 'path';

const envLocalPath = path.resolve('.env.local');
const envContent = fs.readFileSync(envLocalPath, 'utf-8');
const supabaseUrl = envContent.match(/VITE_SUPABASE_URL=(.*)/)?.[1]?.trim();
const supabaseAnonKey = envContent.match(/VITE_SUPABASE_ANON_KEY=(.*)/)?.[1]?.trim();

console.log('Supabase URL:', supabaseUrl);

const supabase = createClient(supabaseUrl, supabaseAnonKey);

async function checkDatabase() {
  try {
    const { data: weddings, error: wError } = await supabase
      .from('weddings')
      .select('*');
    if (wError) throw wError;
    console.log('\n--- WEDDINGS ---');
    console.log(JSON.stringify(weddings, null, 2));

    const { data: guests, error: gError } = await supabase
      .from('guests')
      .select('*');
    if (gError) throw gError;
    console.log('\n--- GUESTS ---');
    console.log(JSON.stringify(guests, null, 2));

    const { data: tables, error: tError } = await supabase
      .from('tables')
      .select('*');
    if (tError) throw tError;
    console.log('\n--- TABLES ---');
    console.log(JSON.stringify(tables, null, 2));

  } catch (err) {
    console.error('Error querying Supabase:', err);
  }
}

checkDatabase();
"

