"import { createClient } from '@supabase/supabase-js';
import fs from 'fs';
import path from 'path';

const envLocalPath = path.resolve('.env.local');
const envContent = fs.readFileSync(envLocalPath, 'utf-8');
const supabaseUrl = envContent.match(/VITE_SUPABASE_URL=(.*)/)?.[1]?.trim();
const supabaseAnonKey = envContent.match(/VITE_SUPABASE_ANON_KEY=(.*)/)?.[1]?.trim();

const supabase = createClient(supabaseUrl, supabaseAnonKey);

async function testInsert() {
  // Let's create a mock wedding ID or use an existing one
  const weddingId = 'becd53d7-1f38-4e61-a070-6a6c3f818d15'; // Javi & Cris

  console.log('Inserting budget item...');
  const { data: bData, error: bError } = await supabase
    .from('budget_items')
    .insert([{
      id: 'test_b1',
      wedding_id: weddingId,
      category: 'Espacio y catering',
      name: 'Test Budget Item',
      estimated: 1000,
      actual: 1000,
      paid: false
    }])
    .select();
  console.log('Budget insert result:', { bData, bError });

  console.log('Inserting table...');
  const { data: tData, error: tError } = await supabase
    .from('tables')
    .insert([{
      id: 'test_t1',
      wedding_id: weddingId,
      name: 'Mesa Test',
      capacity: 8
    }])
    .select();
  console.log('Table insert result:', { tData, tError });

  console.log('Inserting guest...');
  const { data: gData, error: gError } = await supabase
    .from('guests')
    .insert([{
      id: 'test_g1',
      wedding_id: weddingId,
      name: 'Invitado Test',
      side: 'Novio',
      diet: '',
      status: 'confirmed',
      table_id: null,
      is_child: false
    }])
    .select();
  console.log('Guest insert result:', { gData, gError });
}

testInsert();
"

